mapper.select:
SELECT SUM(pf.total_amount) AS totalAmount,SUM(commission_amt) AS commissionAmt
, pf.monthly
FROM workshop w JOIN profit pf USING(workshop_id)
w.owner_id = #{ownerId}
AND pf.monthly = #{monthly}
GROUP BY pf.monthly ORDER BY pf.monthly

SELECT
SUM(total_amount) AS totalAmount,
SUM(commission_amt) AS commissionAmt

    , monthly

FROM profit

    workshop_id = #{workshopId}

        AND monthly >= #{startMonth}
        AND monthly <= #{endMonth}


        AND monthly = #{monthly}



    GROUP BY monthly
    ORDER BY monthly

SELECT
SUM(total_amount) AS totalAmount,SUM(commission_amt) AS commissionAmt

    , monthly

FROM profit

    program_id = #{programId}

        AND monthly >= #{startMonth}
        AND monthly <= #{endMonth}


        AND monthly = #{monthly}



    GROUP BY monthly
    ORDER BY monthly

SELECT SUM(pf.total_amount) AS totalAmount, SUM(pf.commission_amt) AS commissionAmt, p.program_id AS programId, p.title FROM program p LEFT JOIN profit pf ON p.program_id = pf.program_id
p.workshop_id = #{workshopId}
AND pf.monthly = #{monthly}
GROUP BY p.program_id, p.title ORDER BY totalAmount DESC

mapper.update:
UPDATE profit SET paid_status=#{paidStatus}

,settled_at = NOW()

WHERE workshop_id=#{workshopId} AND monthly = #{monthly}
